FROM jsonb_to_recordset('[{"id": "cap-112-english-reading-passage-24", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(24-25)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(24-25)", "child_qnums": [24, 25]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-26", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(26-27)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": " nest 鳥巢        feather 羽毛", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(26-27)", "child_qnums": [26, 27]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-28", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(28-29)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": " stage 階段   waste 浪費   percentage 百分比", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(28-29)", "child_qnums": [28, 29]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-30", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(30-32)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Sometimes when the rain falls hard and fast on you, it might hurt a little.\nBut what happens when it hits a mosquito? A 2012 study says when a\nraindrop falls on a mosquito, it’s like when a bus hits a person. Besides,\nthe little insect is hit by a raindrop about once every 20 seconds.\nSo why don’t we see many dead mosquitoes after it rains?\nA mosquito is as big as a raindrop, but it is much lighter — 0.002 g only. This saves its life\nin raindrop attacks. Because the mosquito is so light, when it is hit by a raindrop, it won’t\nexperience a force that is strong enough to kill it.\nThe study also found that when a mosquito is hit by a raindrop, the insect is pushed by\nthe raindrop and falls together with it. But the mosquito doesn’t get wet easily because it\nis covered with hairs which keep off water.  After dropping about 6 cm, it will roll off the\nraindrop and fly away.\nHowever, this trick isn’t always successful.  If the mosquito flies too low when it is hit by the\nraindrop, it won’t have time to fly off.  Then it will hit the ground and meet its death.\n force 力量", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(30-32)", "child_qnums": [30, 31, 32]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-33", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(33-35)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "You probably have heard Beethoven’s famous piano piece “For Elise,”\nbut do you know who “Elise” was?\nOne story is that Elise was Elisabeth Röckel. She once sang in\nBeethoven’s opera Fidelio, and the two became very good friends.\nBeethoven called her “Elise.”  When Röckel was leaving the city of\nVienna, Beethoven wrote “For Elise” to say goodbye to her.  Another\nstory is that Elise was Therese Malfatti. Beethoven was in love with\nher.  He wrote a piece for her and put “For Therese” on the manuscript.  Malfatti kept the\nmanuscript and left it to her family when she died. Later, a man copied the manuscript\nand wrote “For Elise” by mistake.  There is another possible Elise: Elise Barensfeld.  She\nlearned the piano from Malfatti, the same Malfatti in the second story. To help Malfatti,\nBeethoven wrote the piece for her to use to teach Barensfeld.\nThese are just some guesses about who Elise was. We may never know the right answer.\nNo one knew about the piece until 1867, when the manuscript was found. This was 40 years\nafter Beethoven’s death, so he wasn’t around to tell us who Elise was. Only one thing is for\nsure: “For Elise” will always be enjoyed.                    opera 歌劇 manuscript 手稿\n", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(33-35)", "child_qnums": [33, 34, 35]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-36", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(36-38)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Which would you give a boy for his birthday, a toy truck or a doll? If you choose the\ntruck, well, you’re not alone. Most people think that some toys are for boys and some\nare for girls. We might pick building toys for boys and kitchen toys for girls. But why\ndo we do this? Are boys and girls really born with different interests in toys?\nNo, they are not. Children start to show different interests in toys at age three, but\nonly because at this time, they begin to learn about gender and to follow what others\nof their gender do. If you give a girl kitchen toys, she will think they are girls’ toys\nbecause she sees other girls playing with them. But if you give a girl a toy car and\nshow her a group of girls who are playing with cars, she’ll play with the toy car and\nthink it is a girls’ toy. This “watch and follow” habit often becomes a rule for both\nboys and girls in choosing the “right” toys.\nHowever, this rule can be bad for children. Different toys teach children different\nthings. Dolls help with their early language use, and building toys are good for\nlearning math and science. By playing with different toys, children can find out what\nthey are interested in or what they are good at. If they only play one kind of toy, they\nmay lose this important chance. They may also get a wrong idea about what boys\nor girls are able to do. Some doctors worry that children may use the same kind of\nthinking when they look for jobs in the future. If they do, they may miss something\nmore important than just getting a chance to play with different toys. They may miss\nmany, perhaps better, chances in life.\n gender 性別", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(36-38)", "child_qnums": [36, 37, 38]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-39", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(39-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Marie Colvin was a world-famous war reporter. She was born in New York, USA,\nin 1956 and died in Homs, Syria, in 2012.\nWhen she was a student at Yale University, Colvin decided that she wanted to be a\nreporter in the future. She joined the Sunday Times, a UK newspaper, in 1985 and soon\nbecame its Middle East reporter. Besides the Middle East, she also reported from other\nparts of the world: Chechnya, Kosovo and Sri Lanka, for example.  When she was reporting\non the war in Sri Lanka, she lost her left eye. But that never stopped her. She still went to\ndangerous places that few reporters wanted to visit and stayed when others left.\nColvin showed great empathy in her stories.  For her, war reporting was not just some\nquick interviews and a few photos. She wrote about real people and their real lives. Her\nwriting made you feel so strongly about these people’s stories, just like they were your own.\nShe hoped that through her work the world would understand what really happened in war,\nand would take action to stop the fighting.\nOn February 22, 2012, the day after she gave her report on the war in Homs, Colvin\nwas killed when the house she was staying in was attacked. She always knew what price a\nwar reporter might have to pay. She already lost an eye before. This time, she gave her life\nto the work she could not give up — telling the true stories to the world.\n war 戰爭", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(39-41)", "child_qnums": [39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-english-reading-passage-42", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-112-english-reading", "question_type": "reading_passage", "question_text": "(42-43)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Speaking American is a great book!\nLucia Leisure ★★★★★\nI just love Josh Katz’s new book! It’s about 42 in different parts of the US.\nThe information in the book was collected from the quiz that Katz built on the\nwebsite in 2013. The quiz asked what words people use for something, and their\nanswers showed interesting facts. For example, there are different names for\nsports shoes. In most parts of the US, people say “tennis shoes.” In the northeast\nof the country, people wear “sneakers.” In some towns, “tennis shoes” and\n“sneakers” become “gym shoes.”\nThe use of words tells us where people are from, like Katz’s book says. But in\nmy experience, it also shows 43 . My family has lived in New York since my\ngrandparents. It’s not surprising that I say “sneakers.” But my grandfather says\n“plimsolls,” and my daughter says “kicks” or “vans.” Maybe Katz can study this\ndifference for his next book.\n website 網站", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "cf3633650349", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "(42-43)", "child_qnums": [42, 43]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
